                  </div>
                  
                  {/* ========== المربعات الـ6 (نفس الكود الأصلي - لم نغير شيئاً) ========== */}
                  <div className="manager-cards-container">
                    
                    {/* المربع 1: إدارة الطاولات */}
                    <div className="manager-card">
                      <div className="card-title"><span>🍽️</span> Gestion des tables</div>
                      <div className="input-group">
                        <label>Nombre de nouvelles tables:</label>
                        <input type="number" min="1" max="50" value={newTableCount} onChange={(e) => setNewTableCount(parseInt(e.target.value))} />
                      </div>
                      <div className="input-group">
                        <label>Appartenance au groupe (optionnel):</label>
                        <select value={selectedGroupForTable} onChange={(e) => setSelectedGroupForTable(e.target.value)}>
                          <option value="">Sans groupe</option>
                          {groups.map(g => (<option key={g.id} value={g.id}>Groupe {g.id}: {g.name}</option>))}
                        </select>
                      </div>
                      <button className="btn-primary" onClick={addTables}>➕ Ajouter des tables</button>
                      <div className="table-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Tables actuelles ({tables.length})</h4>
                        {tables.map(table => (
                          <div key={table.id} className="table-item">
                            <span style={{ color: 'white' }}>Table {table.number}</span>
                            <button className="qr-placeholder-btn" onClick={() => showQRPlaceholderFunc(table)}>📱 Code QR</button>
                          </div>
                        ))}
                        {tables.length === 0 && <p style={{ color: 'rgba(255,255,255,0.5)', textAlign: 'center' }}>Aucune table pour le moment</p>}
                      </div>
                    </div>
                    
                    {/* المربع 2: إدارة المجموعات */}
                    <div className="manager-card">
                      <div className="card-title"><span>👥</span> Gestion des groupes</div>
                      <div className="input-group">
                        <label>Nom du nouveau groupe:</label>
                        <input type="text" value={newGroupName} onChange={(e) => setNewGroupName(e.target.value)} placeholder="Exemple: Groupe A" />
                      </div>
                      <button className="btn-primary" onClick={addGroup}>➕ Ajouter un groupe</button>
                      <div className="group-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Groupes actuels ({groups.length})</h4>
                        {groups.map(group => (
                          <div key={group.id} className="group-item">
                            <div>
                              <span style={{ color: 'white', fontWeight: 'bold' }}>{group.name}</span>
                              {group.tableRange.start && (
                                <div style={{ fontSize: '0.8rem', color: '#22c55e' }}>
                                  Tables: {group.tableRange.start} → {group.tableRange.end}
                                </div>
                              )}
                            </div>
                            <button className="btn-secondary" style={{ padding: '5px 10px', fontSize: '0.8rem' }}
                              onClick={() => {
                                const start = prompt("Numéro de début des tables:");
                                const end = prompt("Numéro de fin des tables:");
                                if (start && end) assignTablesToGroup(group.id, parseInt(start), parseInt(end));
                              }}>🪑 Assigner des tables</button>
                          </div>
                        ))}
                      </div>
                      <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', marginTop: '10px' }}>⚠️ Une table ne peut pas être dans deux groupes différents</p>
                    </div>
                    
                    {/* المربع 3: ربط الموظفين بالمجموعات */}
                    <div className="manager-card">
                      <div className="card-title"><span>👨‍🍳</span> Lier les employés aux groupes</div>
                      <div className="input-group">
                        <label>Nom du nouvel employé:</label>
                        <input type="text" value={newEmployeeName} onChange={(e) => setNewEmployeeName(e.target.value)} placeholder="Exemple: Ahmed" />
                      </div>
                      <button className="btn-primary" onClick={addEmployee}>➕ Ajouter un employé</button>
                      <div className="employee-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Employés ({employees.length})</h4>
                        {employees.map(emp => (
                          <div key={emp.id} className="employee-item">
                            <div>
                              <span style={{ color: 'white', fontWeight: 'bold' }}>{emp.name}</span>
                              {emp.groupId && (
                                <div style={{ fontSize: '0.8rem', color: '#22c55e' }}>
                                  → {groups.find(g => g.id === emp.groupId)?.name}
                                </div>
                              )}
                            </div>
                            <select value={emp.groupId || ""} onChange={(e) => assignEmployeeToGroup(emp.id, parseInt(e.target.value))}
                              style={{ background: 'rgba(34,197,94,0.2)', border: '1px solid #22c55e', borderRadius: '10px', padding: '5px', color: 'white' }}>
                              <option value="">Sans groupe</option>
                              {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
                            </select>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* المربع 4: تعديل المنيو */}
                    <div className="manager-card">
                      <div className="card-title"><span>📝</span> Modifier le menu</div>
                      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px', flexWrap: 'wrap' }}>
                        <button className="btn-primary" onClick={() => setShowAddProductModal(true)}>➕ Ajouter un produit</button>
                        <button className="btn-secondary" onClick={() => setShowDeleteProductModal(true)}>🗑️ Supprimer un produit</button>
                        <button className="btn-secondary" onClick={() => setShowEditPriceModal(true)}>💰 Modifier le prix</button>
                      </div>
                      <div>
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Aperçu du menu</h4>
                        {menuCategories.map(cat => (
                          <div key={cat.id} style={{ marginBottom: '15px' }}>
                            <h5 style={{ color: cat.color, marginBottom: '5px' }}>{cat.icon} {cat.name}</h5>
                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
                              {cat.products.map(p => (
                                <div key={p.id} style={{ background: 'rgba(0,0,0,0.3)', borderRadius: '10px', padding: '5px 10px', display: 'flex', alignItems: 'center', gap: '5px' }}>
                                  <img src={p.image} alt={p.name} style={{ width: '25px', height: '25px', borderRadius: '5px' }} />
                                  <span style={{ fontSize: '0.75rem', color: 'white' }}>{p.name}</span>
                                  <span style={{ fontSize: '0.7rem', color: '#22c55e' }}>{p.price} DA</span>
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* المربع 5: كرت المطعم */}
                    <div className="manager-card">
                      <div className="card-title"><span>🏪</span> Carte du restaurant</div>
                      <div style={{ textAlign: 'center', marginBottom: '20px' }}>
                        <img src={restaurantCard.logo} alt="logo" style={{ width: '80px', height: '80px', marginBottom: '10px', borderRadius: '50%' }} />
                        <img src={restaurantCard.image} alt="restaurant" style={{ width: '100%', height: '150px', objectFit: 'cover', borderRadius: '15px', marginBottom: '10px' }} />
                        <h3 style={{ color: '#22c55e', marginBottom: '5px' }}>{restaurantCard.name}</h3>
                        <p style={{ color: 'rgba(255,255,255,0.7)' }}>📍 {restaurantCard.location}</p>
                        <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.9rem' }}>{restaurantCard.description}</p>
                        <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem' }}>📞 {restaurantCard.phone}</p>
                        <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.8rem' }}>✉️ {restaurantCard.email}</p>
                      </div>
                      <button className="btn-primary" onClick={() => { setTempRestaurantCard({ ...restaurantCard }); setShowEditRestaurantModal(true); }}>✏️ Modifier la carte</button>
                    </div>
                    
                    {/* المربع 6: الفواتير */}
                    <div className="manager-card">
                      <div className="card-title"><span>📊</span> Factures</div>
                      <div className="input-group">
                        <label>Type de facture:</label>
                        <select value={filterType} onChange={(e) => setFilterType(e.target.value)}>
                          <option value="daily">📅 Quotidienne</option>
                          <option value="monthly">📆 Mensuelle</option>
                          <option value="seasonal">🌿 Saisonnière</option>
                        </select>
                      </div>
                      {filterType === "daily" && (
                        <div className="input-group"><label>Date:</label><input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)} /></div>
                      )}
                      {filterType === "monthly" && (
                        <div style={{ display: 'flex', gap: '10px' }}>
                          <div className="input-group" style={{ flex: 1 }}><label>Mois:</label><select value={selectedMonth} onChange={(e) => setSelectedMonth(parseInt(e.target.value))}>
                            {["Janvier", "Février", "Mars", "Avril", "Mai", "Juin", "Juillet", "Août", "Septembre", "Octobre", "Novembre", "Décembre"].map((m, i) => (<option key={i} value={i}>{m}</option>))}
                          </select></div>
                          <div className="input-group" style={{ flex: 1 }}><label>Année:</label><input type="number" value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} /></div>
                        </div>
                      )}
                      {filterType === "seasonal" && (
                        <div style={{ display: 'flex', gap: '10px' }}>
                          <div className="input-group" style={{ flex: 1 }}><label>Saison:</label><select value={selectedSeason} onChange={(e) => setSelectedSeason(e.target.value)}>
                            <option value="spring">🌸 Printemps (Mars-Mai)</option><option value="summer">☀️ Été (Juin-Août)</option><option value="autumn">🍂 Automne (Septembre-Novembre)</option><option value="winter">❄️ Hiver (Décembre-Février)</option>
                          </select></div>
                          <div className="input-group" style={{ flex: 1 }}><label>Année:</label><input type="number" value={selectedYear} onChange={(e) => setSelectedYear(parseInt(e.target.value))} /></div>
                        </div>
                      )}
                      <button className="btn-primary" onClick={toggleInvoices}>{showInvoices ? "🙈 Masquer les factures" : "🔍 Afficher les factures"}</button>
                      {showInvoices && invoices.length > 0 && (
                        <div className="invoices-container">
                          <div className="invoice-tabs">
                            <button className={`invoice-tab ${invoiceViewType === 'tables' ? 'active' : ''}`} onClick={() => setInvoiceViewType('tables')}>🍽️ Factures par table</button>
                            <button className={`invoice-tab ${invoiceViewType === 'groups' ? 'active' : ''}`} onClick={() => setInvoiceViewType('groups')}>👥 Factures par groupe</button>
                            <button className={`invoice-tab ${invoiceViewType === 'restaurant' ? 'active' : ''}`} onClick={() => setInvoiceViewType('restaurant')}>🏪 Facture du restaurant</button>
                          </div>
                          {invoiceViewType === 'tables' && (
                            <>
                              <div className="invoice-stats"><h3>{getTotalRevenue()} DA</h3><p>Revenu total des tables</p><p style={{ fontSize: '0.8rem' }}>{invoices.length} facture(s)</p></div>
                              <div className="table-list" style={{ maxHeight: '250px' }}>{invoices.slice(0, 10).map(inv => (<div key={inv.id} className="invoice-item"><span>Table {inv.tableNumber}</span><span style={{ color: '#22c55e' }}>{inv.total} DA</span></div>))}</div>
                            </>
                          )}
                          {invoiceViewType === 'groups' && (
                            <>
                              <div className="invoice-stats" style={{ background: 'linear-gradient(135deg, #3b82f6, #1d4ed8)' }}><h3>{groupInvoices.reduce((sum, g) => sum + g.total, 0)} DA</h3><p>Revenu total des groupes</p><p style={{ fontSize: '0.8rem' }}>{groupInvoices.length} groupe(s)</p></div>
                              <div className="table-list" style={{ maxHeight: '250px' }}>{groupInvoices.map(group => (<div key={group.groupId} className="invoice-item group-invoice-item"><div><span style={{ fontWeight: 'bold' }}>{group.groupName}</span><div style={{ fontSize: '0.7rem' }}>{group.tableCount} table(s) • {group.orderCount} commande(s)</div></div><span style={{ color: '#60a5fa' }}>{group.total} DA</span></div>))}</div>
                            </>
                          )}
                          {invoiceViewType === 'restaurant' && restaurantInvoice && (
                            <div className="restaurant-invoice" style={{ padding: '20px', borderRadius: '20px', textAlign: 'center' }}>
                              <div style={{ fontSize: '3rem' }}>🏪</div>
                              <h3 style={{ color: '#22c55e', fontSize: '2.5rem' }}>{restaurantInvoice.total} DA</h3>
                              <p>Revenu total du restaurant</p>
                              <p style={{ fontSize: '0.8rem' }}>{restaurantInvoice.tableCount || restaurantInvoice.orderCount} transaction(s)</p>
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                  
                  {/* السيرة الذاتية والمهارات واللغات (في الأسفل مثل بروفيل العامل) */}
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{managerInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {managerInfo.skills.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}
                        </div>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {managerInfo.languages.map((lang, i) => (<span key={i} className="skill-tag">🌐 {lang}</span>))}
                        </div>
                      </div>
                    </div>
                  </div>
                  
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* ========== MODALS (نفس الكود الأصلي - لم نغير شيئاً) ========== */}
      
      {/* مودال QR Code */}
      {showQRPlaceholder && selectedTableForQR && (
        <div className="modal-overlay" onClick={() => setShowQRPlaceholder(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', textAlign: 'center', marginBottom: '20px' }}>📱 Code QR pour la table {selectedTableForQR.number}</h2>
            <div className="qr-placeholder-box">
              <div style={{ fontSize: '4rem', marginBottom: '10px' }}>📱</div>
              <p style={{ color: '#22c55e', fontWeight: 'bold', marginBottom: '10px' }}>Emplacement du code QR</p>
              <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>Table numéro {selectedTableForQR.number}</p>
              <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem', marginTop: '10px' }}>Le vrai code QR sera ajouté plus tard</p>
            </div>
            <button className="btn-primary" style={{ width: '100%' }} onClick={() => setShowQRPlaceholder(false)}>Fermer</button>
          </div>
        </div>
      )}
      
      {/* مودال إضافة منتج */}
      {showAddProductModal && (
        <div className="modal-overlay" onClick={() => setShowAddProductModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>➕ Ajouter un nouveau produit</h2>
            <div className="input-group"><label>Catégorie:</label><select onChange={(e) => setSelectedCategory(parseInt(e.target.value))}><option value="">Choisir une catégorie</option>{menuCategories.map(cat => (<option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>))}</select></div>
            <div className="input-group"><label>Nom du produit:</label><input type="text" value={newProduct.name} onChange={(e) => setNewProduct({...newProduct, name: e.target.value})} /></div>
            <div className="input-group"><label>Prix (DA):</label><input type="number" value={newProduct.price} onChange={(e) => setNewProduct({...newProduct, price: parseFloat(e.target.value)})} /></div>
            <div className="input-group"><label>Lien de l'image du produit:</label><input type="text" value={newProduct.image} onChange={handleProductImageChange} placeholder="https://example.com/image.jpg" /></div>
            {productImagePreview && (<div style={{ textAlign: 'center' }}><img src={productImagePreview} alt="preview" className="image-preview" /></div>)}
            <button className="btn-primary" style={{ width: '100%' }} onClick={addProduct}>💾 Enregistrer le produit</button>
          </div>
        </div>
      )}
      
      {/* مودال حذف منتج */}
      {showDeleteProductModal && (
        <div className="modal-overlay" onClick={() => setShowDeleteProductModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>🗑️ Supprimer un produit</h2>
            {menuCategories.map(cat => (
              <div key={cat.id} style={{ marginBottom: '20px' }}>
                <h3 style={{ color: cat.color }}>{cat.icon} {cat.name}</h3>
                {cat.products.map(product => (
                  <div key={product.id} className="product-item">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                      <img src={product.image} alt={product.name} style={{ width: '30px', height: '30px', borderRadius: '8px' }} />
                      <span style={{ color: 'white' }}>{product.name}</span>
                    </div>
                    <button className="btn-danger" onClick={() => deleteProduct(cat.id, product.id)}>Supprimer</button>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* مودال تعديل السعر */}
      {showEditPriceModal && (
        <div className="modal-overlay" onClick={() => setShowEditPriceModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>💰 Modifier le prix</h2>
            {menuCategories.map(cat => (
              <div key={cat.id} style={{ marginBottom: '20px' }}>
                <h3 style={{ color: cat.color }}>{cat.icon} {cat.name}</h3>
                {cat.products.map(product => (
                  <div key={product.id} className="product-item">
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                      <img src={product.image} alt={product.name} style={{ width: '30px', height: '30px', borderRadius: '8px' }} />
                      <span style={{ color: 'white' }}>{product.name}</span>
                    </div>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                      <span style={{ color: '#22c55e' }}>{product.price} DA</span>
                      <button className="btn-secondary" onClick={() => { const newPrice = prompt("Nouveau prix:", product.price); if (newPrice) updateProductPrice(cat.id, product.id, parseFloat(newPrice)); }}>Modifier</button>
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        </div>
      )}
      
      {/* مودال تعديل كرت المطعم */}
      {showEditRestaurantModal && (
        <div className="modal-overlay" onClick={() => setShowEditRestaurantModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px' }}>✏️ Modifier la carte du restaurant</h2>
            <div className="input-group"><label>Nom du restaurant:</label><input type="text" value={tempRestaurantCard.name} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, name: e.target.value})} /></div>
            <div className="input-group"><label>Emplacement:</label><input type="text" value={tempRestaurantCard.location} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, location: e.target.value})} /></div>
            <div className="input-group"><label>Description:</label><textarea rows="3" value={tempRestaurantCard.description} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, description: e.target.value})} /></div>
            <div className="input-group"><label>Téléphone:</label><input type="text" value={tempRestaurantCard.phone} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, phone: e.target.value})} /></div>
            <div className="input-group"><label>Email:</label><input type="email" value={tempRestaurantCard.email} onChange={(e) => setTempRestaurantCard({...tempRestaurantCard, email: e.target.value})} /></div>
            <div className="input-group"><label>Lien du logo:</label><input type="text" value={tempRestaurantCard.logo} onChange={handleRestaurantLogoChange} placeholder="https://example.com/logo.jpg" /></div>
            <div className="input-group"><label>Lien de l'image du restaurant:</label><input type="text" value={tempRestaurantCard.image} onChange={handleRestaurantImageChange} placeholder="https://example.com/restaurant.jpg" /></div>
            {restaurantImagePreview && (<div style={{ textAlign: 'center' }}><img src={restaurantImagePreview} alt="restaurant preview" className="image-preview" /></div>)}
            <button className="btn-primary" style={{ width: '100%' }} onClick={updateRestaurantCard}>💾 Enregistrer les modifications</button>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
